import React from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import {
  Drawer,
  List,
  ListItem,
  ListItemButton,
  ListItemIcon,
  ListItemText,
  Divider,
  Box,
  Typography,
  Avatar,
} from '@mui/material';
import {
  Dashboard as DashboardIcon,
  Analytics as AnalyticsIcon,
  Warning as WarningIcon,
  FitnessCenter as RehabIcon,
  Settings as SettingsIcon,
  MonitorHeart,
  TrendingUp,
} from '@mui/icons-material';

const drawerWidth = 280;

const menuItems = [
  { text: 'Dashboard', icon: <DashboardIcon />, path: '/', color: '#8B5CF6' },
  { text: 'Posture Analysis', icon: <AnalyticsIcon />, path: '/analysis', color: '#EC4899' },
  { text: 'Risk Assessment', icon: <WarningIcon />, path: '/risk', color: '#F59E0B' },
  { text: 'Rehabilitation', icon: <RehabIcon />, path: '/rehabilitation', color: '#10B981' },
  { text: 'Settings', icon: <SettingsIcon />, path: '/settings', color: '#06B6D4' },
];

const Sidebar = ({ open }) => {
  const navigate = useNavigate();
  const location = useLocation();

  return (
    <Drawer
      variant="persistent"
      anchor="left"
      open={open}
      sx={{
        width: drawerWidth,
        flexShrink: 0,
        '& .MuiDrawer-paper': {
          width: drawerWidth,
          boxSizing: 'border-box',
          mt: 10,
          background: (theme) => 
            theme.palette.mode === 'dark' 
              ? 'linear-gradient(180deg, #0A0A0F 0%, #1A1A2E 50%, #16213E 100%)'
              : 'linear-gradient(180deg, #FFFFFF 0%, #F8FAFC 50%, #E2E8F0 100%)',
          backdropFilter: 'blur(20px)',
          borderRight: (theme) => 
            theme.palette.mode === 'dark'
              ? '1px solid rgba(139, 92, 246, 0.3)'
              : '1px solid rgba(124, 58, 237, 0.2)',
          '&::before': {
            content: '""',
            position: 'absolute',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            background: (theme) => 
              theme.palette.mode === 'dark'
                ? 'radial-gradient(circle at 50% 0%, rgba(139, 92, 246, 0.1) 0%, transparent 50%)'
                : 'radial-gradient(circle at 50% 0%, rgba(124, 58, 237, 0.05) 0%, transparent 50%)',
            pointerEvents: 'none',
          },
        },
      }}
    >
      <Box sx={{ p: 3, textAlign: 'center', position: 'relative', zIndex: 1 }}>
        <Avatar
          sx={{
            width: 80,
            height: 80,
            mx: 'auto',
            mb: 2,
            background: 'linear-gradient(135deg, #8B5CF6 0%, #EC4899 100%)',
            boxShadow: '0 0 40px rgba(139, 92, 246, 0.5)',
            border: '3px solid rgba(255, 255, 255, 0.1)',
            backdropFilter: 'blur(10px)',
          }}
        >
          <MonitorHeart sx={{ fontSize: 40, color: '#FFFFFF' }} />
        </Avatar>
        <Typography 
          variant="h6" 
          sx={{ 
            fontWeight: 800,
            background: (theme) => 
              theme.palette.mode === 'dark'
                ? 'linear-gradient(135deg, #8B5CF6 0%, #EC4899 100%)'
                : 'linear-gradient(135deg, #7C3AED 0%, #DB2777 100%)',
            WebkitBackgroundClip: 'text',
            WebkitTextFillColor: 'transparent',
            backgroundClip: 'text',
            mb: 1,
          }}
        >
          SpineSense Pro
        </Typography>
        <Typography 
          variant="body2" 
          sx={{ 
            color: 'text.secondary',
            opacity: 0.8,
            fontWeight: 500,
          }}
        >
          Advanced Posture Analytics
        </Typography>
      </Box>
      
      <Divider 
        sx={{ 
          mx: 2,
          background: (theme) => 
            theme.palette.mode === 'dark'
              ? 'linear-gradient(90deg, transparent, rgba(139, 92, 246, 0.5), transparent)'
              : 'linear-gradient(90deg, transparent, rgba(124, 58, 237, 0.3), transparent)',
          height: 2,
          border: 'none',
        }} 
      />
      
      <List sx={{ px: 2, py: 3 }}>
        {menuItems.map((item, index) => (
          <ListItem key={item.text} disablePadding sx={{ mb: 1 }}>
            <ListItemButton
              onClick={() => navigate(item.path)}
              selected={location.pathname === item.path}
              sx={{
                borderRadius: 3,
                py: 1.5,
                px: 2,
                position: 'relative',
                overflow: 'hidden',
                transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
                '&.Mui-selected': {
                  background: `linear-gradient(135deg, ${item.color}20 0%, ${item.color}10 100%)`,
                  border: `1px solid ${item.color}40`,
                  color: item.color,
                  transform: 'translateX(8px)',
                  boxShadow: `0 8px 32px ${item.color}30`,
                  '&::before': {
                    content: '""',
                    position: 'absolute',
                    left: 0,
                    top: 0,
                    bottom: 0,
                    width: 4,
                    background: `linear-gradient(180deg, ${item.color} 0%, ${item.color}80 100%)`,
                    borderRadius: '0 4px 4px 0',
                    boxShadow: `0 0 20px ${item.color}`,
                  },
                  '&:hover': {
                    background: `linear-gradient(135deg, ${item.color}30 0%, ${item.color}15 100%)`,
                    transform: 'translateX(12px)',
                  },
                  '& .MuiListItemIcon-root': {
                    color: item.color,
                    filter: `drop-shadow(0 0 8px ${item.color}50)`,
                  },
                  '& .MuiListItemText-primary': {
                    fontWeight: 700,
                    color: item.color,
                  },
                },
                '&:hover': {
                  background: (theme) => 
                    theme.palette.mode === 'dark'
                      ? 'rgba(139, 92, 246, 0.08)'
                      : 'rgba(124, 58, 237, 0.05)',
                  transform: 'translateX(4px)',
                },
                '&::after': {
                  content: '""',
                  position: 'absolute',
                  top: 0,
                  left: '-100%',
                  width: '100%',
                  height: '100%',
                  background: `linear-gradient(90deg, transparent, ${item.color}20, transparent)`,
                  transition: 'left 0.5s',
                },
                '&:hover::after': {
                  left: '100%',
                },
              }}
            >
              <ListItemIcon
                sx={{
                  minWidth: 48,
                  color: location.pathname === item.path ? item.color : 'text.secondary',
                  transition: 'all 0.3s ease',
                }}
              >
                {item.icon}
              </ListItemIcon>
              <ListItemText 
                primary={item.text}
                primaryTypographyProps={{
                  fontWeight: location.pathname === item.path ? 700 : 500,
                  fontSize: '0.95rem',
                }}
              />
              {location.pathname === item.path && (
                <Box
                  sx={{
                    width: 8,
                    height: 8,
                    borderRadius: '50%',
                    background: `linear-gradient(135deg, ${item.color} 0%, ${item.color}80 100%)`,
                    boxShadow: `0 0 12px ${item.color}`,
                    animation: 'pulse 2s infinite',
                    '@keyframes pulse': {
                      '0%': {
                        transform: 'scale(1)',
                        opacity: 1,
                      },
                      '50%': {
                        transform: 'scale(1.2)',
                        opacity: 0.7,
                      },
                      '100%': {
                        transform: 'scale(1)',
                        opacity: 1,
                      },
                    },
                  }}
                />
              )}
            </ListItemButton>
          </ListItem>
        ))}
      </List>

      {/* Status Indicator */}
      <Box 
        sx={{ 
          position: 'absolute',
          bottom: 20,
          left: 20,
          right: 20,
          p: 2,
          borderRadius: 3,
          background: (theme) => 
            theme.palette.mode === 'dark'
              ? 'linear-gradient(135deg, rgba(16, 185, 129, 0.1) 0%, rgba(6, 182, 212, 0.1) 100%)'
              : 'linear-gradient(135deg, rgba(16, 185, 129, 0.05) 0%, rgba(6, 182, 212, 0.05) 100%)',
          border: '1px solid rgba(16, 185, 129, 0.3)',
          backdropFilter: 'blur(10px)',
        }}
      >
        <Box sx={{ display: 'flex', alignItems: 'center', mb: 1 }}>
          <Box
            sx={{
              width: 8,
              height: 8,
              borderRadius: '50%',
              background: 'linear-gradient(135deg, #10B981 0%, #059669 100%)',
              boxShadow: '0 0 12px rgba(16, 185, 129, 0.6)',
              mr: 1,
              animation: 'pulse 2s infinite',
            }}
          />
          <Typography variant="caption" sx={{ color: '#10B981', fontWeight: 600 }}>
            System Online
          </Typography>
        </Box>
        <Typography variant="caption" sx={{ color: 'text.secondary', fontSize: '0.75rem' }}>
          All sensors connected
        </Typography>
      </Box>
    </Drawer>
  );
};

export default Sidebar;
